<template>
	<div
		ref="dragTargetRef"
		:class="[`absolute cursor-grab active:cursor-grabbing transform-gpu ${className}`]"
		:style="cssVars"
	>
		<svg width="0" height="0">
			<defs>
				<filter id="pointLight">
					<feGaussianBlur stdDeviation="1" result="blur" />
					<feSpecularLighting
						result="spec"
						in="blur"
						:specularExponent="100"
						:specularConstant="props.lightingIntensity"
						lighting-color="white"
					>
						<fePointLight ref="pointLightRef" :x="100" :y="100" :z="300" />
					</feSpecularLighting>
					<feComposite in="spec" in2="SourceGraphic" result="lit" />
					<feComposite in="lit" in2="SourceAlpha" operator="in" />
				</filter>

				<filter id="pointLightFlipped">
					<feGaussianBlur stdDeviation="10" result="blur" />
					<feSpecularLighting
						result="spec"
						in="blur"
						:specularExponent="100"
						:specularConstant="flippedLightingConstant"
						lighting-color="white"
					>
						<fePointLight ref="pointLightFlippedRef" :x="100" :y="100" :z="300" />
					</feSpecularLighting>
					<feComposite in="spec" in2="SourceGraphic" result="lit" />
					<feComposite in="lit" in2="SourceAlpha" operator="in" />
				</filter>

				<filter id="dropShadow">
					<feDropShadow
						dx="2"
						dy="4"
						:stdDeviation="dropShadowStdDeviation"
						flood-color="black"
						:flood-opacity="props.shadowIntensity"
					/>
				</filter>

				<filter id="expandAndFill">
					<feOffset dx="0" dy="0" in="SourceAlpha" result="shape" />
					<feFlood flood-color="rgb(179,179,179)" result="flood" />
					<feComposite operator="in" in="flood" in2="shape" />
				</filter>
			</defs>
		</svg>

		<div
			ref="containerRef"
			class="relative touch-none sm:touch-auto select-none sticker-container"
			:style="{
  WebkitUserSelect: 'none',
  userSelect: 'none',
  WebkitTouchCallout: 'none',
  WebkitTapHighlightColor: 'transparent',
  transform: `rotate(${peelDirection}deg)`,
  transformOrigin: 'center'
}"
		>
			<div class="sticker-main" :style="stickerMainStyle">
				<div :style="{ filter: 'url(#pointLight)' }">
					<img :src="props.imageSrc" alt="" class="block" :style="imageStyle" draggable="false" @contextmenu.prevent>
				</div>

				<div class="top-4 left-2 absolute opacity-40 w-full h-full" :style="{ filter: 'brightness(0) blur(8px)' }">
					<div class="sticker-flap" :style="flapStyle">
						<img
							:src="props.imageSrc"
							alt=""
							class="block"
							:style="shadowImageStyle"
							draggable="false"
							@contextmenu.prevent
						>
					</div>
				</div>

				<div class="left-0 absolute w-full h-full sticker-flap" :style="flapStyle">
					<div :style="{ filter: 'url(#pointLightFlipped)' }">
						<img
							:src="props.imageSrc"
							alt=""
							class="block"
							:style="shadowImageStyle"
							draggable="false"
							@contextmenu.prevent
						>
					</div>
				</div>
			</div>
		</div>
	</div>
</template>

<script setup>
import { gsap } from "gsap";
import { Draggable } from "gsap/Draggable";
import { computed, onBeforeUnmount, onMounted, ref, useTemplateRef, watch } from "vue";
const props = defineProps({
  imageSrc: { type: String, required: true },
  rotate: { type: Number, required: false, default: 30 },
  peelBackHoverPct: { type: Number, required: false, default: 30 },
  peelBackActivePct: { type: Number, required: false, default: 40 },
  peelEasing: { type: String, required: false, default: "power3.out" },
  peelHoverEasing: { type: String, required: false, default: "power2.out" },
  width: { type: Number, required: false, default: 200 },
  shadowIntensity: { type: Number, required: false, default: 0.6 },
  lightingIntensity: { type: Number, required: false, default: 0.1 },
  initialPosition: { type: [String, Object], required: false, default: "center" },
  peelDirection: { type: Number, required: false, default: 0 },
  className: { type: String, required: false, default: "" }
});
gsap.registerPlugin(Draggable);
const containerRef = useTemplateRef("containerRef");
const dragTargetRef = useTemplateRef("dragTargetRef");
const pointLightRef = useTemplateRef("pointLightRef");
const pointLightFlippedRef = useTemplateRef("pointLightFlippedRef");
const draggableInstanceRef = ref(null);
const defaultPadding = 12;
let cleanup = null;
const setup = () => {
  const target = dragTargetRef.value;
  if (!target) return;
  const boundsEl = target.parentNode;
  const draggable = Draggable.create(target, {
    type: "x,y",
    bounds: boundsEl,
    inertia: true,
    onDrag() {
      const rot = gsap.utils.clamp(-24, 24, this.deltaX * 0.4);
      gsap.to(target, { rotation: rot, duration: 0.15, ease: "power1.out" });
    },
    onDragEnd() {
      const rotationEase = "power2.out";
      const duration = 0.8;
      gsap.to(target, { rotation: 0, duration, ease: rotationEase });
    }
  });
  if (draggable[0]) draggableInstanceRef.value = draggable[0];
  const handleResize = () => {
    if (draggableInstanceRef.value) {
      draggableInstanceRef.value.update();
      const currentX = gsap.getProperty(target, "x");
      const currentY = gsap.getProperty(target, "y");
      const boundsRect = boundsEl.getBoundingClientRect();
      const targetRect = target.getBoundingClientRect();
      const maxX = boundsRect.width - targetRect.width;
      const maxY = boundsRect.height - targetRect.height;
      const newX = Math.max(0, Math.min(currentX, maxX));
      const newY = Math.max(0, Math.min(currentY, maxY));
      if (newX !== currentX || newY !== currentY) {
        gsap.to(target, {
          x: newX,
          y: newY,
          duration: 0.3,
          ease: "power2.out"
        });
      }
    }
  };
  window.addEventListener("resize", handleResize);
  window.addEventListener("orientationchange", handleResize);
  const container = containerRef.value;
  if (!container) return;
  const handleTouchStart = () => {
    container.classList.add("touch-active");
  };
  const handleTouchEnd = () => {
    container.classList.remove("touch-active");
  };
  container.addEventListener("touchstart", handleTouchStart);
  container.addEventListener("touchend", handleTouchEnd);
  container.addEventListener("touchcancel", handleTouchEnd);
  cleanup = () => {
    window.removeEventListener("resize", handleResize);
    window.removeEventListener("orientationchange", handleResize);
    if (draggableInstanceRef.value) {
      draggableInstanceRef.value.kill();
    }
    container.removeEventListener("touchstart", handleTouchStart);
    container.removeEventListener("touchend", handleTouchEnd);
    container.removeEventListener("touchcancel", handleTouchEnd);
  };
};
onMounted(() => {
  setup();
});
watch(
  () => props.initialPosition,
  () => {
    const target = dragTargetRef.value;
    if (!target) return;
    let startX = 0;
    let startY = 0;
    if (props.initialPosition === "center") {
      return;
    }
    if (typeof props.initialPosition === "object" && props.initialPosition.x !== void 0 && props.initialPosition.y !== void 0) {
      startX = props.initialPosition.x;
      startY = props.initialPosition.y;
    }
    gsap.set(target, { x: startX, y: startY });
  },
  { immediate: true }
);
let lightHandler = null;
watch(
  () => props.peelDirection,
  () => {
    const updateLight = (e) => {
      const mouseEvent = e;
      const rect = containerRef.value?.getBoundingClientRect();
      if (!rect) return;
      const x = mouseEvent.clientX - rect.left;
      const y = mouseEvent.clientY - rect.top;
      if (pointLightRef.value) {
        gsap.set(pointLightRef.value, { attr: { x, y } });
      }
      const normalizedAngle = Math.abs(props.peelDirection % 360);
      if (pointLightFlippedRef.value) {
        if (normalizedAngle !== 180) {
          gsap.set(pointLightFlippedRef.value, {
            attr: { x, y: rect.height - y }
          });
        } else {
          gsap.set(pointLightFlippedRef.value, {
            attr: { x: -1e3, y: -1e3 }
          });
        }
      }
    };
    const container = containerRef.value;
    const eventType = "mousemove";
    if (container) {
      container.addEventListener(eventType, updateLight);
      lightHandler = () => container.removeEventListener(eventType, updateLight);
    }
  },
  { immediate: true }
);
onBeforeUnmount(() => {
  const container = containerRef.value;
  if (container && lightHandler) {
    lightHandler();
    lightHandler = null;
  }
  if (cleanup) {
    cleanup();
    cleanup = null;
  }
});
const cssVars = computed(() => ({
  "--sticker-rotate": `${props.rotate}deg`,
  "--sticker-p": `${defaultPadding}px`,
  "--sticker-peelback-hover": `${props.peelBackHoverPct}%`,
  "--sticker-peelback-active": `${props.peelBackActivePct}%`,
  "--sticker-peel-easing": props.peelEasing,
  "--sticker-peel-hover-easing": props.peelHoverEasing,
  "--sticker-width": `${props.width}px`,
  "--sticker-shadow-opacity": props.shadowIntensity,
  "--sticker-lighting-constant": props.lightingIntensity,
  "--peel-direction": `${props.peelDirection}deg`,
  "--sticker-start": `calc(-1 * ${defaultPadding}px)`,
  "--sticker-end": `calc(100% + ${defaultPadding}px)`
}));
const stickerMainStyle = computed(() => ({
  clipPath: `polygon(var(--sticker-start) var(--sticker-start), var(--sticker-end) var(--sticker-start), var(--sticker-end) var(--sticker-end), var(--sticker-start) var(--sticker-end))`,
  transition: "clip-path 0.6s ease-out",
  filter: "url(#dropShadow)",
  willChange: "clip-path, transform"
}));
const flapStyle = computed(() => ({
  clipPath: `polygon(var(--sticker-start) var(--sticker-start), var(--sticker-end) var(--sticker-start), var(--sticker-end) var(--sticker-start), var(--sticker-start) var(--sticker-start))`,
  top: `calc(-100% - var(--sticker-p) - var(--sticker-p))`,
  transform: "scaleY(-1)",
  transition: "all 0.6s ease-out",
  willChange: "clip-path, transform"
}));
const imageStyle = computed(() => ({
  transform: `rotate(calc(${props.rotate}deg - ${props.peelDirection}deg))`,
  width: `${props.width}px`
}));
const shadowImageStyle = computed(() => ({
  ...imageStyle.value,
  filter: "url(#expandAndFill)"
}));
const dropShadowStdDeviation = computed(() => 3 * props.shadowIntensity);
const flippedLightingConstant = computed(() => props.lightingIntensity * 7);
</script>

<style scoped>
.sticker-container.touch-active .sticker-main,.sticker-container:hover .sticker-main{clip-path:polygon(var(--sticker-start) var(--sticker-peelback-hover),var(--sticker-end) var(--sticker-peelback-hover),var(--sticker-end) var(--sticker-end),var(--sticker-start) var(--sticker-end))!important}.sticker-container.touch-active .sticker-flap,.sticker-container:hover .sticker-flap{clip-path:polygon(var(--sticker-start) var(--sticker-start),var(--sticker-end) var(--sticker-start),var(--sticker-end) var(--sticker-peelback-hover),var(--sticker-start) var(--sticker-peelback-hover))!important;top:calc(-100% + var(--sticker-peelback-hover)*2 - 1px)!important}.sticker-container:active .sticker-main{clip-path:polygon(var(--sticker-start) var(--sticker-peelback-active),var(--sticker-end) var(--sticker-peelback-active),var(--sticker-end) var(--sticker-end),var(--sticker-start) var(--sticker-end))!important}.sticker-container:active .sticker-flap{clip-path:polygon(var(--sticker-start) var(--sticker-start),var(--sticker-end) var(--sticker-start),var(--sticker-end) var(--sticker-peelback-active),var(--sticker-start) var(--sticker-peelback-active))!important;top:calc(-100% + var(--sticker-peelback-active)*2 - 1px)!important}
</style>
